/**
 * AUTO-GENERATED bởi scripts/gen-snippets.mjs — ĐỪNG SỬA TAY.
 * Nguồn: nocobase-plugins/snippets/*.js. Sửa snippet nguồn rồi chạy lại generator.
 */
export type FieldSnippet = {
  ref: string;
  prefix: string;
  label: string;
  description: string;
  contexts: string[];
  content: string;
};

export const FIELD_SNIPPETS: FieldSnippet[] = [
  {
    "ref": "ptdl/field/input-icon",
    "prefix": "input-icon",
    "label": "Input icon + placeholder",
    "description": "Text/password input với icon lucide ở prefix, placeholder tự lấy từ tên field (kiểu login form).",
    "contexts": [
      "JSEditableFieldModel",
      "FormJSFieldItemModel"
    ],
    "content": "/**\n * Input icon + placeholder-from-title — Run JS (JS field trong Form Create/Edit)\n * Thêm icon lucide vào prefix của Input/Input.Password và tự set placeholder = tiêu đề field\n * (ctx.collectionField.title) thay vì hiện label phía trên — giống mẫu login (icon user/lock trong ô input).\n *\n * Cách dùng: field trong Form → menu field → \"JS field\" → dán code này (thay code mặc định) → chỉnh CONFIG.\n * Để giống ảnh mẫu 100%: mở thêm \"Form item settings\" > \"Show label\" của field này và TẮT đi (bước có sẵn\n * của NocoBase, không cần code) — placeholder sẽ đóng vai trò label.\n */\n\n// ================== CẤU HÌNH ==================\nconst ICON = 'user'; // tên icon lucide, bare kebab (vd 'user', 'lock', 'mail', 'phone')\nconst ICON_SIZE = 16;\nconst ICON_COLOR = '#8c8c8c';\nconst USE_TITLE_AS_PLACEHOLDER = true; // true: placeholder = ctx.collectionField.title\nconst PLACEHOLDER_OVERRIDE = ''; // không rỗng thì dùng chuỗi này thay vì title\nconst IS_PASSWORD = false; // true: dùng Input.Password (ẩn ký tự, có icon mắt của antd)\n// ==============================================\n\nfunction InputWithIcon() {\n  const React = ctx.React;\n  const { Input } = ctx.antd;\n  const { useState, useEffect } = React;\n  const [value, setValue] = useState(ctx.getValue?.() ?? '');\n  const [iconHtml, setIconHtml] = useState('');\n\n  useEffect(() => {\n    const handler = (ev) => setValue(ev?.detail ?? '');\n    ctx.element?.addEventListener('js-field:value-change', handler);\n    return () => ctx.element?.removeEventListener('js-field:value-change', handler);\n  }, []);\n\n  // Icon lucide qua CDN — RunJS không đọc được registry icon nội bộ của @nocobase/client-v2,\n  // đây là cách đúng cho RunJS (xem docs/ICON-ARCHITECTURE.md). Version khớp lucide-react mà\n  // @ptdl/plugin-custom-icons pin (0.469.0).\n  useEffect(() => {\n    let cancelled = false;\n    (async () => {\n      try {\n        const lucide = await ctx.requireAsync('lucide@0.469.0/dist/umd/lucide.min.js');\n        const pascal = ICON.split('-')\n          .map((s) => s.charAt(0).toUpperCase() + s.slice(1))\n          .join('');\n        const iconNode = lucide.icons[pascal];\n        if (!iconNode) throw new Error(`Không tìm thấy icon lucide: ${ICON}`);\n        const el = lucide.createElement(iconNode);\n        el.setAttribute('width', ICON_SIZE);\n        el.setAttribute('height', ICON_SIZE);\n        el.setAttribute('stroke', ICON_COLOR);\n        if (!cancelled) setIconHtml(el.outerHTML);\n      } catch (e) {\n        if (!cancelled) setIconHtml('');\n      }\n    })();\n    return () => {\n      cancelled = true;\n    };\n  }, []);\n\n  const onChange = (e) => {\n    const v = e?.target?.value ?? '';\n    setValue(v);\n    ctx.setValue?.(v);\n  };\n\n  const placeholder =\n    PLACEHOLDER_OVERRIDE || (USE_TITLE_AS_PLACEHOLDER ? ctx.collectionField?.title || '' : undefined);\n\n  const prefix = iconHtml ? (\n    <span style={{ display: 'inline-flex', lineHeight: 0 }} dangerouslySetInnerHTML={{ __html: iconHtml }} />\n  ) : null;\n\n  if (ctx.readOnly) {\n    return <span>{String(value ?? '')}</span>;\n  }\n\n  const InputComp = IS_PASSWORD ? Input.Password : Input;\n\n  return <InputComp value={value} onChange={onChange} placeholder={placeholder} prefix={prefix} disabled={ctx.disabled} />;\n}\n\nctx.render(<InputWithIcon />);\n"
  },
  {
    "ref": "ptdl/field/rich-select",
    "prefix": "rich-select",
    "label": "Rich association dropdown",
    "description": "Dropdown chọn record quan hệ (m2o/o2o/o2m/m2m) — mỗi option 2 dòng: avatar + tên + chức vụ + icon trạng thái.",
    "contexts": [
      "JSEditableFieldModel",
      "FormJSFieldItemModel"
    ],
    "content": "/**\n * Rich association select — Run JS (JS field, thay cho \"Dropdown select\" mặc định của field quan hệ m2o/o2o/o2m/m2m)\n * Mỗi option hiển thị nhiều thông tin hơn 1 dòng chữ:\n *\n *   [Avatar][Tên]                                     [Active icon]\n *   [      ][Chức vụ]\n *\n * - Cột trái: avatar (căn trên, dùng chữ cái đầu của tên nếu không có ảnh)\n * - Cột phải, dòng 1: tên + icon trạng thái active (nếu bật)\n * - Cột phải, dòng 2: chức vụ (dòng phụ, màu xám nhạt)\n * Ô đóng / tag (khi chưa mở dropdown) hiện gọn avatar + tên (không icon/chức vụ) cho đỡ rối.\n *\n * QUAN TRỌNG — đây là field quan hệ (association), khác field chọn giá trị đơn thuần:\n * - Bảng phụ + field khoá TỰ LẤY từ field hiện tại (`ctx.collectionField.target` / `.targetCollection.filterTargetKey`),\n *   không cần khai TARGET_COLLECTION/VALUE_FIELD tay — đúng bảng quan hệ đã cấu hình ở Collection, không hard-code.\n * - Value ghi vào form là NGUYÊN RECORD (object) đã chọn — vd `{id, nickname, avatar, position, status}` — chứ KHÔNG\n *   phải chỉ mỗi id, giống đúng cách field \"Dropdown select\" gốc của NocoBase lưu (xem RecordSelectFieldModel.tsx,\n *   Select dùng labelInValue/lưu cả option). Field kiểu m2m/o2m tự chuyển sang mode nhiều (mảng record).\n * - Nếu record NocoBase trả về ban đầu (appends) thiếu field hiển thị (vd chỉ có id) → tự fetch bổ sung 1 lần khi mount.\n *\n * Cách dùng: field quan hệ trong Form → menu field → \"JS field\" → dán code này → chỉnh LABEL_FIELD/SUBTITLE_FIELD/\n * AVATAR_FIELD/ACTIVE_FIELD cho khớp cột thật của bảng đích.\n */\n\n// ================== CẤU HÌNH ==================\nconst LABEL_FIELD = 'nickname'; // tên hiển thị chính (dòng 1)\nconst SUBTITLE_FIELD = 'position'; // chức vụ (dòng 2) — để '' nếu không có field này\nconst AVATAR_FIELD = 'avatar'; // field ảnh — hỗ trợ url string, hoặc object/array attachment {url}\nconst ACTIVE_FIELD = 'status'; // field boolean — hiện icon khi true, để '' nếu không cần icon trạng thái\nconst SEARCH_FIELD = LABEL_FIELD; // field dùng để lọc khi gõ tìm kiếm (server-side, kiểu $includes)\nconst APPENDS = []; // quan hệ cần appends thêm (vd AVATAR_FIELD là field quan hệ riêng của bảng đích thì thêm vào đây)\nconst PAGE_SIZE = 30;\nconst PLACEHOLDER = 'Chọn...';\nconst ACTIVE_ICON = 'circle-check'; // tên icon lucide (bare kebab)\nconst ACTIVE_ICON_COLOR = '#52c41a';\nconst AVATAR_SIZE = 32;\n// Override thủ công — để trống ('') thì tự lấy theo field quan hệ hiện tại (khuyến nghị, không cần đụng vào)\nconst TARGET_COLLECTION_OVERRIDE = '';\nconst VALUE_FIELD_OVERRIDE = '';\nconst MULTIPLE_OVERRIDE = null; // null = tự nhận theo collectionField.type (m2m/o2m → nhiều; m2o/o2o → 1)\n// ==============================================\n\nconst DEBUG = false; // bật true để log ra console: target collection, valueField, kết quả fetch — dùng khi field không hiện gì\n\nconst targetCollectionName = TARGET_COLLECTION_OVERRIDE || ctx.collectionField?.target;\nconst valueField = VALUE_FIELD_OVERRIDE || ctx.collectionField?.targetCollection?.filterTargetKey || 'id';\nconst isMultiple =\n  MULTIPLE_OVERRIDE ?? ['belongsToMany', 'hasMany', 'belongsToArray'].includes(ctx.collectionField?.type);\n\nif (DEBUG) {\n  console.log('[runjs-record-select-rich] collectionField:', ctx.collectionField);\n  console.log('[runjs-record-select-rich] targetCollectionName:', targetCollectionName, 'valueField:', valueField, 'isMultiple:', isMultiple);\n}\n\nfunction avatarSrc(record) {\n  const v = record?.[AVATAR_FIELD];\n  if (!v) return undefined;\n  if (typeof v === 'string') return v;\n  if (Array.isArray(v)) return v[0]?.url;\n  return v.url;\n}\n\nfunction RichAssociationSelect() {\n  const React = ctx.React;\n  const { Select, Avatar, Spin, Empty } = ctx.antd;\n  const { useState, useEffect, useRef, useCallback } = React;\n\n  const [value, setValue] = useState(ctx.getValue?.() ?? (isMultiple ? [] : undefined));\n  const [options, setOptions] = useState([]);\n  const [loading, setLoading] = useState(false);\n  const [activeIconHtml, setActiveIconHtml] = useState('');\n  const recordsRef = useRef(new Map()); // String(valueField) -> record, dùng cho optionRender/readOnly/hydrate\n\n  const searchTimerRef = useRef(null);\n\n  useEffect(() => {\n    const handler = (ev) => setValue(ev?.detail ?? (isMultiple ? [] : undefined));\n    ctx.element?.addEventListener('js-field:value-change', handler);\n    return () => ctx.element?.removeEventListener('js-field:value-change', handler);\n  }, []);\n\n  // Icon lucide cho trạng thái active — load qua CDN (RunJS không đọc được registry icon nội bộ, xem\n  // docs/ICON-ARCHITECTURE.md). Version khớp lucide-react mà @ptdl/plugin-custom-icons pin (0.469.0).\n  useEffect(() => {\n    if (!ACTIVE_FIELD) return;\n    let cancelled = false;\n    (async () => {\n      try {\n        const lucide = await ctx.requireAsync('lucide@0.469.0/dist/umd/lucide.min.js');\n        const pascal = ACTIVE_ICON.split('-')\n          .map((s) => s.charAt(0).toUpperCase() + s.slice(1))\n          .join('');\n        const iconNode = lucide.icons[pascal];\n        if (!iconNode) return;\n        const el = lucide.createElement(iconNode);\n        el.setAttribute('width', 14);\n        el.setAttribute('height', 14);\n        el.setAttribute('stroke', ACTIVE_ICON_COLOR);\n        if (!cancelled) setActiveIconHtml(el.outerHTML);\n      } catch (_) {\n        // Tải icon lỗi (CDN down...) → bỏ qua, vẫn hiện tên/avatar bình thường\n      }\n    })();\n    return () => {\n      cancelled = true;\n    };\n  }, []);\n\n  const rememberRecord = (record) => {\n    if (record?.[valueField] != null) recordsRef.current.set(String(record[valueField]), record);\n    return record;\n  };\n\n  const toOption = (record) => ({ value: record[valueField], label: record[LABEL_FIELD], record: rememberRecord(record) });\n\n  const fetchOptions = useCallback(async (search) => {\n    setLoading(true);\n    try {\n      const res = await ctx.api.request({\n        url: `${targetCollectionName}:list`,\n        method: 'get',\n        params: {\n          pageSize: PAGE_SIZE,\n          appends: APPENDS.length ? APPENDS : undefined,\n          filter: search ? { [SEARCH_FIELD]: { $includes: search } } : undefined,\n        },\n      });\n      const list = res?.data?.data || [];\n      if (DEBUG) console.log('[runjs-record-select-rich] fetched', list.length, 'record(s):', list);\n      setOptions(list.map(toOption));\n    } catch (e) {\n      if (DEBUG) console.error('[runjs-record-select-rich] fetch error:', e);\n      ctx.message?.error?.(e.message || 'Tải danh sách thất bại');\n    } finally {\n      setLoading(false);\n    }\n    // eslint-disable-next-line react-hooks/exhaustive-deps\n  }, []);\n\n  // Tải lần đầu + hydrate record đang chọn nếu thiếu field hiển thị (vd form chỉ có {id} do server không append đủ)\n  useEffect(() => {\n    (async () => {\n      await fetchOptions('');\n      const current = ctx.getValue?.();\n      const items = isMultiple ? (Array.isArray(current) ? current : []) : current ? [current] : [];\n      items.forEach(rememberRecord);\n      const missing = items.filter((it) => it?.[valueField] != null && it[LABEL_FIELD] == null);\n      if (!missing.length) return;\n      if (DEBUG) console.log('[runjs-record-select-rich] hydrating missing:', missing);\n      try {\n        const res = await ctx.api.request({\n          url: `${targetCollectionName}:list`,\n          method: 'get',\n          params: {\n            filter: { [valueField]: { $in: missing.map((it) => it[valueField]) } },\n            appends: APPENDS.length ? APPENDS : undefined,\n          },\n        });\n        (res?.data?.data || []).forEach(rememberRecord);\n        const merge = (it) => (it?.[valueField] != null ? recordsRef.current.get(String(it[valueField])) || it : it);\n        setValue((prev) => (isMultiple ? (Array.isArray(prev) ? prev.map(merge) : prev) : merge(prev)));\n      } catch (_) {\n        // Không hydrate được (record đã xoá...) → vẫn hiện value thô, không chặn form\n      }\n    })();\n    // eslint-disable-next-line react-hooks/exhaustive-deps\n  }, []);\n\n  const onSearch = (text) => {\n    clearTimeout(searchTimerRef.current);\n    searchTimerRef.current = setTimeout(() => fetchOptions(text), 300);\n  };\n\n  const onChange = (_v, option) => {\n    const next = isMultiple\n      ? (Array.isArray(option) ? option : []).map((o) => o.record)\n      : option?.record ?? null;\n    setValue(next);\n    ctx.setValue?.(next);\n  };\n\n  const renderRow = (record, compact) => {\n    if (!record) return null;\n    // Fallback lộ ra ngay khi LABEL_FIELD cấu hình sai tên cột (không tồn tại ở bảng đích) — thay vì hiện trống\n    // im lặng, hiện value thô kèm dấu ? để dễ nhận ra cần sửa CẤU HÌNH.\n    const name = record[LABEL_FIELD] ?? (record[valueField] != null ? `#${record[valueField]} (?)` : '');\n    const subtitle = SUBTITLE_FIELD ? record[SUBTITLE_FIELD] : '';\n    const active = ACTIVE_FIELD ? !!record[ACTIVE_FIELD] : false;\n    const src = avatarSrc(record);\n    return (\n      <div style={{ display: 'flex', alignItems: compact ? 'center' : 'flex-start', gap: 8, minWidth: 0 }}>\n        <Avatar src={src} size={compact ? 22 : AVATAR_SIZE} style={{ flexShrink: 0 }}>\n          {!src && name ? name.charAt(0).toUpperCase() : null}\n        </Avatar>\n        <div style={{ flex: 1, minWidth: 0 }}>\n          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 8 }}>\n            <span style={{ fontWeight: 500, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>\n              {name}\n            </span>\n            {!compact && active && activeIconHtml ? (\n              <span\n                style={{ display: 'inline-flex', lineHeight: 0, flexShrink: 0 }}\n                dangerouslySetInnerHTML={{ __html: activeIconHtml }}\n              />\n            ) : null}\n          </div>\n          {!compact && subtitle ? <div style={{ fontSize: 12, color: '#8c8c8c' }}>{subtitle}</div> : null}\n        </div>\n      </div>\n    );\n  };\n\n  if (ctx.readOnly) {\n    if (isMultiple) {\n      const list = Array.isArray(value) ? value : [];\n      return (\n        <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>\n          {list.map((rec, i) => (\n            <React.Fragment key={rec?.[valueField] ?? i}>{renderRow(rec, true)}</React.Fragment>\n          ))}\n        </div>\n      );\n    }\n    return value ? renderRow(value, true) : <span style={{ color: '#bfbfbf' }}>-</span>;\n  }\n\n  return (\n    <Select\n      mode={isMultiple ? 'multiple' : undefined}\n      value={isMultiple ? (Array.isArray(value) ? value.map((r) => r?.[valueField]) : []) : value?.[valueField]}\n      onChange={onChange}\n      onSearch={onSearch}\n      showSearch\n      filterOption={false}\n      allowClear\n      loading={loading}\n      disabled={ctx.disabled}\n      placeholder={PLACEHOLDER}\n      // Tắt virtual scroll: Select mặc định dùng rc-virtual-list, tự đo chiều cao mỗi dòng theo 1 hàng đơn (~32px).\n      // Option của mình cao 2 dòng (avatar+tên+chức vụ) hơn mức đó → nội dung bị virtual-list cắt/che mất, dropdown\n      // hiện trắng trơn dù data đã fetch đủ. Tắt virtual để list tự đo chiều cao thật theo nội dung render.\n      virtual={false}\n      style={{ width: '100%' }}\n      popupMatchSelectWidth={false}\n      notFoundContent={\n        loading ? <Spin size=\"small\" /> : <Empty image={Empty.PRESENTED_IMAGE_SIMPLE} description=\"Không có kết quả\" />\n      }\n      options={options}\n      optionRender={(option) => renderRow(option?.data?.record ?? option?.record, false)}\n      // Dùng thẳng `value` (state) — đây LÀ record đang chọn, không tra qua recordsRef (ref không kích hoạt\n      // re-render khi được cập nhật → nếu tra theo ref, lần render đầu của field đã có sẵn giá trị (sửa record cũ)\n      // sẽ ra null vì ref chưa kịp có data, khiến ô hiện trống dù value không rỗng).\n      labelRender={() => renderRow(isMultiple ? null : value, true)}\n      tagRender={(props) => {\n        const record =\n          (Array.isArray(value) && value.find((r) => String(r?.[valueField]) === String(props.value))) ||\n          recordsRef.current.get(String(props.value));\n        return (\n          <span\n            style={{\n              display: 'inline-flex',\n              alignItems: 'center',\n              gap: 4,\n              margin: '2px 4px 2px 0',\n              padding: '1px 6px 1px 2px',\n              border: '1px solid #d9d9d9',\n              borderRadius: 999,\n              background: '#fafafa',\n            }}\n          >\n            {renderRow(record, true)}\n            <span style={{ cursor: 'pointer', color: '#8c8c8c' }} onMouseDown={(e) => e.preventDefault()} onClick={props.onClose}>\n              ×\n            </span>\n          </span>\n        );\n      }}\n    />\n  );\n}\n\nctx.render(<RichAssociationSelect />);\n"
  },
  {
    "ref": "ptdl/field/select-buttons",
    "prefix": "select-buttons",
    "label": "Select → button group",
    "description": "Field select/multi-select hiển thị thành dãy nút thay vì dropdown; tự lấy option + màu từ field.",
    "contexts": [
      "JSEditableFieldModel",
      "FormJSFieldItemModel",
      "JSColumnModel"
    ],
    "content": "/**\n * Select → Button group — Run JS (JS Column / JS editable field trong form)\n * Hiển thị field select/multi-select thành dãy NÚT thay vì dropdown — sửa nhanh khi option ít (2-3 mục).\n * - Single select → nút kiểu Radio (chọn đúng 1, có thể bỏ chọn nếu ALLOW_DESELECT)\n * - Multi select  → nút kiểu Checkbox (bấm nhiều nút, độc lập bật/tắt từng nút)\n *\n * COLOR_MODE:\n * - 'colorful' → mỗi option 1 màu riêng, KẾ THỪA màu đã cấu hình trên field (Edit field → chỉnh màu từng option).\n * - 'mono'     → chỉ 1 màu (MONO_COLOR) cho nút đang active, các nút khác trung tính (xám) — mặc định lấy màu\n *                primary theo theme qua CSS var `--colorPrimaryTextActive` (NocoBase tự set sẵn trên <body>),\n *                không lấy được thì fallback về xanh dương antd.\n *\n * LAYOUT:\n * - 'separated' → mỗi nút tách rời, viền riêng, có khoảng cách (kiểu hiện tại).\n * - 'joined'    → dính thành 1 khối kiểu segmented control (nền track xám nhạt, nút active nổi lên nền trắng).\n *\n * ICONS: mapping icon lucide theo TỪNG value (key = String(value) của option) — để trống = không hiện icon,\n * không tốn tải lucide. Icon dùng màu currentColor nên tự đổi màu theo COLOR_MODE/trạng thái active như chữ.\n *\n * RADIUS: số (px) hoặc 'full' (bo tròn hết cỡ, kiểu pill/segmented tròn).\n *\n * FONT_SIZE: số (px) — để `null` thì tự theo SIZE ('small'=12px, 'default'=13px) như trước.\n *\n * Tự nhận diện ngữ cảnh:\n * - Form Create/Edit (JS editable field): ghi qua ctx.setValue — bấm Save của form mới lưu\n * - JS Column (bảng): gọi API update — lưu ngay\n */\n\n// ================== CẤU HÌNH ==================\nconst FIELD          = 'status'; // tên field select/multi-select trên record\nconst MODE            = 'auto';  // 'auto' | 'single' | 'multi' — auto: tự nhận theo field.interface\nconst ALLOW_DESELECT  = true;    // (single) bấm lại nút đang chọn → bỏ chọn (value = null)\nconst SIZE             = 'default'; // 'small' | 'default' — quyết định padding của nút\nconst FONT_SIZE         = null;     // số (px), vd 15 — để null thì tự theo SIZE (small=12px, default=13px)\nconst GAP              = 6;         // khoảng cách giữa các nút — chỉ áp dụng khi LAYOUT='separated' (px)\nconst COLOR_MODE       = 'colorful'; // 'colorful' | 'mono'\nconst MONO_COLOR       = 'var(--colorPrimaryTextActive, #1677ff)'; // màu dùng khi COLOR_MODE='mono'\nconst LAYOUT           = 'separated'; // 'separated' | 'joined'\nconst RADIUS           = 4; // số (px) hoặc 'full' (bo tròn hết cỡ)\nconst ICON_SIZE         = 14; // kích thước icon (px)\n// Icon lucide theo từng value — key PHẢI là String(value) của option (vd value số 1 → key '1')\nconst ICONS = {\n  // todo: 'circle',\n  // doing: 'loader',\n  // done: 'check-circle',\n};\n// Fallback khi KHÔNG lấy được option từ field (vd chạy trong JS Block không gắn collection) — điền tay:\nconst OPTIONS_FALLBACK = [\n  // { value: 'todo', label: 'To do', color: 'default' },\n  // { value: 'doing', label: 'Doing', color: 'blue' },\n  // { value: 'done', label: 'Done', color: 'green' },\n];\n\n// Preset màu chuẩn antd — field select của NocoBase chọn màu option từ đúng bộ này\nconst PRESET_HEX = {\n  red: '#f5222d', volcano: '#fa541c', orange: '#fa8c16', gold: '#faad14',\n  yellow: '#fadb14', lime: '#a0d911', green: '#52c41a', cyan: '#13c2c2',\n  blue: '#1677ff', geekblue: '#2f54eb', purple: '#722ed1', magenta: '#eb2f96',\n  default: '#8c8c8c',\n};\n\n// ==============================================\nfunction toHex(color) {\n  if (!color) return PRESET_HEX.default;\n  if (PRESET_HEX[color]) return PRESET_HEX[color];\n  if (/^#|^rgb/i.test(color)) return color;\n  return PRESET_HEX.default;\n}\n\n// Màu \"chủ đạo\" của 1 option theo COLOR_MODE — dùng chung cho cả 2 layout\nfunction colorFor(opt) {\n  return COLOR_MODE === 'mono' ? MONO_COLOR : toHex(opt.color);\n}\n\nfunction radiusPx(base) {\n  return RADIUS === 'full' ? 999 : (RADIUS ?? base);\n}\n\n// Cache icon SVG (name → outerHTML) — chỉ tải lucide nếu ICONS có cấu hình, tải 1 lần rồi dùng lại cho mọi lần vẽ.\n// stroke=\"currentColor\" nên icon tự đổi màu theo `color` của button (active/inactive/mono/colorful) mà không cần tính riêng.\nlet iconCache = {};\nasync function loadIconCache() {\n  const names = Object.values(ICONS).filter(Boolean);\n  if (!names.length) return;\n  try {\n    // Load qua CDN (RunJS không truy cập được registry icon nội bộ @nocobase/client-v2 — xem\n    // docs/ICON-ARCHITECTURE.md). Version khớp lucide-react mà @ptdl/plugin-custom-icons pin (provider đang active).\n    const lucide = await ctx.requireAsync('lucide@0.469.0/dist/umd/lucide.min.js');\n    for (const name of new Set(names)) {\n      const pascal = name.split('-').map((s) => s.charAt(0).toUpperCase() + s.slice(1)).join('');\n      const iconNode = lucide.icons[pascal];\n      if (!iconNode) continue;\n      const el = lucide.createElement(iconNode);\n      el.setAttribute('width', ICON_SIZE);\n      el.setAttribute('height', ICON_SIZE);\n      el.setAttribute('stroke', 'currentColor');\n      iconCache[name] = el.outerHTML;\n    }\n  } catch (_) {\n    // Tải icon lỗi (CDN down...) → bỏ qua, nút vẫn hiện chữ bình thường\n  }\n}\n\nfunction iconFor(opt) {\n  const name = ICONS[String(opt.value)];\n  if (!name || !iconCache[name]) return '';\n  return `<span style=\"display:inline-flex;line-height:0\">${iconCache[name]}</span>`;\n}\n\nconst output = (html) =>\n  typeof ctx.render === 'function' ? ctx.render(html) : (ctx.element.innerHTML = html);\n\nconst isFormField = typeof ctx.setValue === 'function' && typeof ctx.getValue === 'function';\nconst canEdit = isFormField\n  ? !ctx.readOnly && !ctx.disabled\n  : !!(ctx.record && ctx.collection && typeof ctx.api?.request === 'function');\nlet saving = false;\n\n// Lấy định nghĩa field (nếu ctx.collection có sẵn) để suy ra: danh sách option (value/label/color) + single hay multi\nconst fieldDef = ctx.collection?.getField?.(FIELD);\nconst options = (fieldDef?.enum?.length ? fieldDef.enum : OPTIONS_FALLBACK) || [];\nconst isMulti = MODE === 'auto' ? fieldDef?.interface === 'multipleSelect' : MODE === 'multi';\n\nasync function save(newVal) {\n  if (isFormField) {\n    // Trong form: chỉ ghi vào giá trị form — bấm Save của form mới thực sự lưu\n    ctx.setValue(newVal);\n    return;\n  }\n  const tk = ctx.collection?.getFilterByTK?.(ctx.record);\n  if (tk === null || tk === undefined) throw new Error('Không xác định được khóa của record');\n  await ctx.api.request({\n    url: `${ctx.collection.name}:update`,\n    method: 'post',\n    params: { filterByTk: tk },\n    data: { [FIELD]: newVal },\n  });\n  try { ctx.record[FIELD] = newVal; } catch (_) { /* record read-only thì bỏ qua */ }\n}\n\nlet lastDrawn;\n\nfunction draw(raw) {\n  lastDrawn = raw;\n\n  if (!options.length) {\n    output('<span style=\"color:#bfbfbf\">Chưa có option (kiểm tra FIELD hoặc điền OPTIONS_FALLBACK)</span>');\n    return;\n  }\n\n  const selected = isMulti\n    ? new Set(Array.isArray(raw) ? raw : raw != null ? [raw] : [])\n    : new Set(raw != null ? [raw] : []);\n\n  const pad = SIZE === 'small' ? '2px 10px' : '4px 14px';\n  const fontSize = FONT_SIZE ?? (SIZE === 'small' ? 12 : 13);\n  const cursor = canEdit ? 'cursor:pointer' : 'cursor:default';\n\n  let btns, wrapStyle;\n\n  if (LAYOUT === 'joined') {\n    // Kiểu segmented: track nền xám nhạt, nút active nổi lên nền trắng + shadow nhẹ\n    const itemRadius = radiusPx(4);\n    const trackRadius = RADIUS === 'full' ? 999 : itemRadius + 2;\n    btns = options\n      .map((opt) => {\n        const active = selected.has(opt.value);\n        const color = active ? colorFor(opt) : '#8c8c8c';\n        const style = active\n          ? `background:#fff;color:${color};box-shadow:0 1px 2px rgba(0,0,0,.08)`\n          : `background:transparent;color:${color}`;\n        return `<button type=\"button\" data-val=\"${String(opt.value)}\" ${canEdit ? '' : 'disabled'}\n          style=\"${style};${cursor};padding:${pad};font-size:${fontSize}px;border:none;border-radius:${itemRadius}px;line-height:1.4;font-weight:${active ? 500 : 400};transition:all .15s;display:inline-flex;align-items:center;gap:4px\">\n          ${iconFor(opt)}<span>${opt.label ?? opt.value}</span>\n        </button>`;\n      })\n      .join('');\n    wrapStyle = `display:inline-flex;align-items:center;gap:2px;background:#f0f0f0;padding:2px;border-radius:${trackRadius}px`;\n  } else {\n    // Kiểu tách rời: mỗi nút viền riêng\n    const itemRadius = radiusPx(4);\n    btns = options\n      .map((opt) => {\n        const active = selected.has(opt.value);\n        const color = colorFor(opt);\n        const style = active\n          ? `background:${color};border-color:${color};color:#fff`\n          : COLOR_MODE === 'mono'\n            ? 'background:#fff;border-color:#d9d9d9;color:#595959'\n            : `background:#fff;border-color:${color}88;color:${color}`;\n        return `<button type=\"button\" data-val=\"${String(opt.value)}\" ${canEdit ? '' : 'disabled'}\n          style=\"${style};${cursor};padding:${pad};font-size:${fontSize}px;border-width:1px;border-style:solid;border-radius:${itemRadius}px;line-height:1.4;font-weight:${active ? 500 : 400};transition:all .15s;display:inline-flex;align-items:center;gap:4px\">\n          ${iconFor(opt)}<span>${opt.label ?? opt.value}</span>\n        </button>`;\n      })\n      .join('');\n    wrapStyle = `display:inline-flex;flex-wrap:wrap;align-items:center;gap:${GAP}px`;\n  }\n\n  output(`<span data-btn-group style=\"${wrapStyle}\">${btns}</span>`);\n\n  if (!canEdit) return;\n  const wrap = ctx.element?.querySelector?.('[data-btn-group]');\n  if (!wrap) return;\n  wrap.addEventListener('click', async (e) => {\n    const btn = e.target?.closest?.('[data-val]');\n    if (!btn || saving) return;\n    e.stopPropagation();\n\n    // Khớp lại value gốc (đúng kiểu number/string/boolean) từ chuỗi data-val\n    const matched = options.find((o) => String(o.value) === btn.getAttribute('data-val'));\n    if (!matched) return;\n\n    let nextVal;\n    if (isMulti) {\n      const current = Array.isArray(lastDrawn) ? [...lastDrawn] : [];\n      const idx = current.findIndex((v) => v === matched.value);\n      if (idx >= 0) current.splice(idx, 1);\n      else current.push(matched.value);\n      nextVal = current;\n    } else {\n      const isSame = lastDrawn === matched.value;\n      nextVal = isSame && ALLOW_DESELECT ? null : matched.value;\n    }\n\n    saving = true;\n    try {\n      await save(nextVal);\n      draw(nextVal);\n    } catch (err) {\n      ctx.message?.error?.(err.message || 'Cập nhật thất bại');\n    } finally {\n      saving = false;\n    }\n  });\n}\n\n// Tải icon (nếu có cấu hình ICONS) rồi mới vẽ lần đầu — tránh vẽ thiếu icon do CDN chưa kịp trả về\nawait loadIconCache();\n\n// Giá trị ban đầu: form dùng ctx.getValue(), JS Column dùng ctx.record, JS Field dùng ctx.value\ndraw(isFormField ? ctx.getValue() : ctx.record ? ctx.record?.[FIELD] : ctx.value);\n\n// Form: vẽ lại khi giá trị bị đổi từ bên ngoài (reset form, linkage, submit xong...)\nif (isFormField) {\n  ctx.element?.addEventListener?.('js-field:value-change', (ev) => {\n    draw(ev?.detail);\n  });\n}\n"
  },
  {
    "ref": "ptdl/field/checkbox",
    "prefix": "checkbox",
    "label": "Checkbox (toggle / icon)",
    "description": "Field boolean hiển thị dạng switch hoặc icon lucide; bấm để đổi (form ghi qua Save, bảng lưu ngay).",
    "contexts": [
      "JSEditableFieldModel",
      "FormJSFieldItemModel",
      "JSColumnModel",
      "JSFieldModel"
    ],
    "content": "/**\n * Checkbox display — Run JS (JS Column / JS Field)\n * Hiển thị giá trị boolean theo 2 kiểu: 'toggle' (switch) | 'icon' (lucide)\n * EDITABLE = true: bấm vào để bật/tắt. Tự nhận diện ngữ cảnh:\n * - Form Create/Edit (dùng \"JS field\" nhóm editable): ghi vào form qua ctx.setValue — bấm Save mới lưu\n * - JS Column (bảng): gọi API update — lưu ngay\n */\n\n// ================== CẤU HÌNH ==================\nconst FIELD      = 'checkbox';      // tên field checkbox trong record\nconst STYLE      = 'icon';          // 'toggle' | 'icon'\nconst EDITABLE   = true;            // true: bấm để đổi giá trị\nconst ON_COLOR   = '#52c41a';       // màu trạng thái bật\nconst OFF_COLOR  = '#d9d9d9';       // màu trạng thái tắt\nconst SIZE       = 18;              // kích thước icon (px) — chỉ dùng cho STYLE 'icon'\nconst ICON_ON    = 'circle-check';  // icon lucide khi bật  (gợi ý khác: 'square-check', 'toggle-right')\nconst ICON_OFF   = 'circle';        // icon lucide khi tắt  (gợi ý khác: 'square', 'toggle-left')\nconst FILLED     = true;            // true: icon bật kiểu nền đặc + dấu check trắng\nconst CHECK_COLOR = '#fff';         // màu dấu check khi FILLED\nconst SHOW_LABEL = false;           // hiện chữ bên cạnh\nconst LABELS     = { on: 'Bật', off: 'Tắt' };\nconst NULL_AS_OFF = true;           // true: null/undefined coi là tắt; false: hiện '-'\n\n// ==============================================\nconst output = (html) =>\n  typeof ctx.render === 'function' ? ctx.render(html) : (ctx.element.innerHTML = html);\n\n// Nhận diện ngữ cảnh: JS editable field trong form có ctx.getValue/ctx.setValue\nconst isFormField = typeof ctx.setValue === 'function' && typeof ctx.getValue === 'function';\nconst canEdit = EDITABLE\n  ? (isFormField\n      ? !ctx.readOnly && !ctx.disabled\n      : !!(ctx.record && ctx.collection && typeof ctx.api?.request === 'function'))\n  : false;\nlet saving = false;\n\nasync function save(newVal) {\n  if (isFormField) {\n    // Trong form: chỉ ghi vào giá trị form — bấm Save của form mới thực sự lưu\n    ctx.setValue(newVal);\n    return;\n  }\n  const tk = ctx.collection?.getFilterByTK?.(ctx.record);\n  if (tk === null || tk === undefined) throw new Error('Không xác định được khóa của record');\n  await ctx.api.request({\n    url: `${ctx.collection.name}:update`,\n    method: 'post',\n    params: { filterByTk: tk },\n    data: { [FIELD]: newVal },\n  });\n  try { ctx.record[FIELD] = newVal; } catch (_) { /* record read-only thì bỏ qua */ }\n}\n\nfunction attachClick(selector, checked) {\n  if (!canEdit) return;\n  const el = ctx.element?.querySelector?.(selector);\n  if (!el) return;\n  el.addEventListener('click', async (e) => {\n    e.stopPropagation();\n    if (saving) return;\n    saving = true;\n    try {\n      await save(!checked);\n      await draw(!checked);\n    } catch (err) {\n      ctx.message?.error?.(err.message || 'Cập nhật thất bại');\n    } finally {\n      saving = false;\n    }\n  });\n}\n\nasync function draw(v) {\n  lastDrawn = v; // để listener value-change không vẽ trùng\n  if ((v === null || v === undefined) && !NULL_AS_OFF) {\n    output('<span style=\"color:#bfbfbf\">-</span>');\n    return;\n  }\n  const checked = v === true || v === 1 || v === '1' || v === 'true';\n  const color = checked ? ON_COLOR : OFF_COLOR;\n  const cursor = canEdit ? 'cursor:pointer' : '';\n  const labelHtml = SHOW_LABEL\n    ? `<span style=\"font-size:12px;color:${checked ? ON_COLOR : '#8c8c8c'}\">${checked ? LABELS.on : LABELS.off}</span>`\n    : '';\n\n  if (STYLE === 'toggle') {\n    // Switch CSS thuần, giống antd Switch\n    const W = 36, H = 20, KNOB = H - 4;\n    output(`\n      <span data-cbx style=\"display:inline-flex;align-items:center;gap:6px;${cursor}\" title=\"${checked ? LABELS.on : LABELS.off}\">\n        <span style=\"position:relative;display:inline-block;width:${W}px;height:${H}px;border-radius:${H / 2}px;background:${color};transition:background .2s\">\n          <span style=\"position:absolute;top:2px;left:${checked ? W - KNOB - 2 : 2}px;width:${KNOB}px;height:${KNOB}px;border-radius:50%;background:#fff;box-shadow:0 2px 4px rgba(0,0,0,.2);transition:left .2s\"></span>\n        </span>\n        ${labelHtml}\n      </span>\n    `);\n    attachClick('[data-cbx]', checked);\n  } else {\n    // Kiểu icon lucide — load qua CDN (ctx.requireAsync). RunJS không truy cập được registry icon nội bộ\n    // của @nocobase/client-v2 (xem docs/ICON-ARCHITECTURE.md), đây là cách đúng cho RunJS. Version khớp\n    // lucide-react mà @ptdl/plugin-custom-icons (provider icon đang active) pin.\n    try {\n      const lucide = await ctx.requireAsync('lucide@0.469.0/dist/umd/lucide.min.js');\n      const name = checked ? ICON_ON : ICON_OFF;\n      const pascal = name.split('-').map((s) => s.charAt(0).toUpperCase() + s.slice(1)).join('');\n      const iconNode = lucide.icons[pascal];\n      if (!iconNode) throw new Error(`Không tìm thấy icon lucide: ${name}`);\n\n      const el = lucide.createElement(iconNode);\n      el.setAttribute('width', SIZE);\n      el.setAttribute('height', SIZE);\n\n      if (checked && FILLED) {\n        // Bật + kiểu fill: nền tô ON_COLOR, dấu check nét trắng\n        el.setAttribute('stroke', CHECK_COLOR);\n        el.setAttribute('stroke-width', 2.5);\n        const box = el.querySelector('rect, circle');\n        if (box) {\n          box.setAttribute('fill', ON_COLOR);\n          box.setAttribute('stroke', ON_COLOR);\n        }\n      } else {\n        el.setAttribute('stroke', color);\n      }\n\n      output(`\n        <span data-cbx style=\"display:inline-flex;align-items:center;gap:6px;line-height:0;${cursor}\" title=\"${checked ? LABELS.on : LABELS.off}\">\n          ${el.outerHTML}${labelHtml}\n        </span>\n      `);\n      attachClick('[data-cbx]', checked);\n    } catch (e) {\n      // Fallback khi CDN lỗi\n      output(`<span data-cbx style=\"color:${color};font-size:${SIZE}px;${cursor}\">${checked ? '☑' : '☐'}</span>`);\n      attachClick('[data-cbx]', checked);\n    }\n  }\n}\n\n// Giá trị ban đầu: form dùng ctx.getValue(), JS Column dùng ctx.record, JS Field dùng ctx.value\nlet lastDrawn;\nawait draw(isFormField ? ctx.getValue() : (ctx.record ? ctx.record?.[FIELD] : ctx.value));\n\n// Form: vẽ lại khi giá trị bị đổi từ bên ngoài (reset form, linkage, submit xong...)\nif (isFormField) {\n  ctx.element?.addEventListener?.('js-field:value-change', (ev) => {\n    const v = ev?.detail;\n    if (v === lastDrawn) return;\n    lastDrawn = v;\n    void draw(v);\n  });\n}\n"
  },
  {
    "ref": "ptdl/field/star",
    "prefix": "star",
    "label": "Star rating",
    "description": "Số (vd 3.5) → dãy icon rating 3 trạng thái fill/half/empty; editable click-to-set.",
    "contexts": [
      "JSEditableFieldModel",
      "FormJSFieldItemModel",
      "JSColumnModel",
      "JSFieldModel"
    ],
    "content": "/**\n * Rating icon — Run JS (JS Column / JS Field)\n * Hiển thị giá trị số (vd 3.5) thành dãy icon 3 trạng thái: Fill / Half / Empty\n * Icon mặc định: lucide \"star\" — đổi ICON thành icon lucide bất kỳ (kebab-case)\n * EDITABLE = true: bấm vào icon để chấm điểm. Tự nhận diện ngữ cảnh:\n * - Form Create/Edit (dùng \"JS field\" nhóm editable): ghi vào form qua ctx.setValue — bấm Save mới lưu\n * - JS Column (bảng): gọi API update — lưu ngay\n */\n\n// ================== CẤU HÌNH ==================\nconst FIELD       = 'rating';   // tên field lấy giá trị từ record (JS Column)\nconst ICON        = 'star';     // icon lucide bất kỳ: 'star', 'heart', 'thumbs-up', 'flame'...\nconst MAX         = 5;          // tổng số icon\nconst EDITABLE    = true;       // true: bấm icon để chấm điểm\nconst ALLOW_HALF  = true;       // true: bấm nửa trái icon = điểm lẻ .5\nconst CLICK_AGAIN_CLEARS = true; // bấm lại đúng điểm hiện tại → xóa về 0\nconst SIZE        = 18;         // kích thước px\nconst FILL_COLOR  = '#fadb14';  // màu trạng thái Fill / Half\nconst EMPTY_COLOR = '#d9d9d9';  // màu trạng thái Empty\nconst SHOW_NUMBER = true;       // hiện số bên cạnh dãy icon\n\n// ==============================================\nconst output = (html) =>\n  typeof ctx.render === 'function' ? ctx.render(html) : (ctx.element.innerHTML = html);\n\n// Nhận diện ngữ cảnh: JS editable field trong form có ctx.getValue/ctx.setValue\nconst isFormField = typeof ctx.setValue === 'function' && typeof ctx.getValue === 'function';\nconst canEdit = EDITABLE\n  ? (isFormField\n      ? !ctx.readOnly && !ctx.disabled\n      : !!(ctx.record && ctx.collection && typeof ctx.api?.request === 'function'))\n  : false;\nlet saving = false;\n\nasync function save(newRaw) {\n  if (isFormField) {\n    // Trong form: chỉ ghi vào giá trị form — bấm Save của form mới thực sự lưu\n    ctx.setValue(newRaw);\n    return;\n  }\n  const tk = ctx.collection?.getFilterByTK?.(ctx.record);\n  if (tk === null || tk === undefined) throw new Error('Không xác định được khóa của record');\n  await ctx.api.request({\n    url: `${ctx.collection.name}:update`,\n    method: 'post',\n    params: { filterByTk: tk },\n    data: { [FIELD]: newRaw },\n  });\n  try { ctx.record[FIELD] = newRaw; } catch (_) { /* record read-only thì bỏ qua */ }\n}\n\nasync function draw(raw) {\n  lastDrawn = raw; // để listener value-change không vẽ trùng\n  // Làm tròn về bước 0.5 để chia 3 trạng thái Fill / Half / Empty\n  const value = Math.max(0, Math.min(MAX, Math.round(raw * 2) / 2));\n  const cursor = canEdit ? 'cursor:pointer' : '';\n\n  try {\n    // Load lucide qua CDN (ctx.requireAsync — UMD). RunJS không truy cập được registry icon nội bộ\n    // của @nocobase/client-v2 (xem docs/ICON-ARCHITECTURE.md) nên đây là cách đúng cho RunJS, không phải\n    // vi phạm pattern provider/consumer — RunJS không phải \"plugin bundle\". Version khớp lucide-react mà\n    // @ptdl/plugin-custom-icons (provider icon đang active) pin, để tránh lệch tên icon giữa các version.\n    const lucide = await ctx.requireAsync('lucide@0.469.0/dist/umd/lucide.min.js');\n\n    // 'thumbs-up' -> 'ThumbsUp' (key trong lucide.icons là PascalCase)\n    const pascal = ICON.split('-').map((s) => s.charAt(0).toUpperCase() + s.slice(1)).join('');\n    const iconNode = lucide.icons[pascal];\n    if (!iconNode) throw new Error(`Không tìm thấy icon lucide: ${ICON}`);\n\n    const svg = (filled) => {\n      const el = lucide.createElement(iconNode);\n      el.setAttribute('width', SIZE);\n      el.setAttribute('height', SIZE);\n      el.setAttribute('fill', filled ? FILL_COLOR : 'none');\n      el.setAttribute('stroke', filled ? FILL_COLOR : EMPTY_COLOR);\n      return el.outerHTML;\n    };\n\n    const FILL = svg(true);\n    const EMPTY = svg(false);\n    // Half = icon Empty làm nền + icon Fill phủ lên, cắt 50% bề ngang → dùng được với MỌI icon\n    const HALF =\n      EMPTY +\n      `<span style=\"position:absolute;left:0;top:0;width:50%;height:100%;overflow:hidden;pointer-events:none\">${FILL}</span>`;\n\n    let icons = '';\n    for (let i = 1; i <= MAX; i++) {\n      const inner = value >= i ? FILL : value >= i - 0.5 ? HALF : EMPTY;\n      icons += `<span data-i=\"${i}\" style=\"position:relative;display:inline-block;width:${SIZE}px;height:${SIZE}px;line-height:0;${cursor}\">${inner}</span>`;\n    }\n\n    const numberHtml = SHOW_NUMBER\n      ? `<span style=\"margin-left:6px;font-size:12px;color:#8c8c8c\">${raw}</span>`\n      : '';\n\n    output(\n      `<span data-stars title=\"${raw}/${MAX}${canEdit ? ' — bấm để chấm điểm' : ''}\" style=\"display:inline-flex;align-items:center;gap:2px\">${icons}${numberHtml}</span>`,\n    );\n\n    if (!canEdit) return;\n    const wrap = ctx.element?.querySelector?.('[data-stars]');\n    if (!wrap) return;\n    wrap.addEventListener('click', async (e) => {\n      e.stopPropagation();\n      if (saving) return;\n      const star = e.target?.closest?.('[data-i]');\n      if (!star) return;\n      saving = true;\n      try {\n        const i = Number(star.getAttribute('data-i'));\n        let newVal = i;\n        if (ALLOW_HALF) {\n          // Bấm nửa trái icon → điểm lẻ .5\n          const rect = star.getBoundingClientRect();\n          if (e.clientX - rect.left < rect.width / 2) newVal = i - 0.5;\n        }\n        if (CLICK_AGAIN_CLEARS && newVal === value) newVal = 0;\n        await save(newVal);\n        await draw(newVal);\n      } catch (err) {\n        ctx.message?.error?.(err.message || 'Cập nhật thất bại');\n      } finally {\n        saving = false;\n      }\n    });\n  } catch (e) {\n    // Fallback khi CDN lỗi: hiển thị bằng ký tự (không hỗ trợ bấm chỉnh)\n    const full = Math.floor(value);\n    const half = value % 1 ? 1 : 0;\n    output(`<span title=\"${e.message}\">${'★'.repeat(full)}${half ? '⯨' : ''}${'☆'.repeat(MAX - full - half)} ${SHOW_NUMBER ? raw : ''}</span>`);\n  }\n}\n\n// Giá trị ban đầu: form dùng ctx.getValue(), JS Column dùng ctx.record, JS Field dùng ctx.value\nlet lastDrawn;\nawait draw(Number((isFormField ? ctx.getValue() : ctx.record ? ctx.record?.[FIELD] : ctx.value) ?? 0));\n\n// Form: vẽ lại khi giá trị bị đổi từ bên ngoài (reset form, linkage, submit xong...)\nif (isFormField) {\n  ctx.element?.addEventListener?.('js-field:value-change', (ev) => {\n    const v = Number(ev?.detail ?? 0);\n    if (v === lastDrawn) return;\n    void draw(v);\n  });\n}\n"
  },
  {
    "ref": "ptdl/field/progress",
    "prefix": "progress",
    "label": "Progress bar",
    "description": "Số 0–100 → thanh tiến độ + %, màu đổi theo ngưỡng; editable click-to-set.",
    "contexts": [
      "JSEditableFieldModel",
      "FormJSFieldItemModel",
      "JSColumnModel",
      "JSFieldModel"
    ],
    "content": "/**\n * Progress bar — Run JS (JS Column / JS Field)\n * Hiển thị giá trị số thành thanh tiến độ + %, màu đổi theo ngưỡng\n * EDITABLE = true: bấm vào vị trí trên thanh để đặt giá trị mới. Tự nhận diện ngữ cảnh:\n * - Form Create/Edit (dùng \"JS field\" nhóm editable): ghi vào form qua ctx.setValue — bấm Save mới lưu\n * - JS Column (bảng): gọi API update — lưu ngay\n */\n\n// ================== CẤU HÌNH ==================\nconst FIELD      = 'amount';   // tên field lấy giá trị từ record (JS Column)\nconst MAX        = 100;        // giá trị coi là 100% (vd field lưu 0–1 thì để MAX = 1)\nconst EDITABLE   = true;       // true: bấm lên thanh để đặt giá trị theo vị trí bấm\nconst STEP       = 5;          // bước làm tròn % khi bấm chỉnh (vd 5 → 0,5,10,...)\nconst SHOW_TEXT  = true;       // hiện số % bên cạnh thanh\nconst DECIMALS   = 0;          // số chữ số thập phân của %\nconst BAR_HEIGHT = 10;         // độ cao thanh (px)\nconst BAR_WIDTH  = 100;        // độ rộng thanh (px); 0 = co giãn theo ô\n// Ngưỡng màu: duyệt từ trên xuống, lấy màu đầu tiên có percent >= min\nconst THRESHOLDS = [\n  { min: 100, color: '#52c41a' }, // xanh lá — hoàn thành\n  { min: 70,  color: '#1677ff' }, // xanh dương\n  { min: 40,  color: '#faad14' }, // vàng\n  { min: 0,   color: '#f5222d' }, // đỏ\n];\n\n// ==============================================\nconst output = (html) =>\n  typeof ctx.render === 'function' ? ctx.render(html) : (ctx.element.innerHTML = html);\n\n// Nhận diện ngữ cảnh: JS editable field trong form có ctx.getValue/ctx.setValue\nconst isFormField = typeof ctx.setValue === 'function' && typeof ctx.getValue === 'function';\nconst canEdit = EDITABLE\n  ? (isFormField\n      ? !ctx.readOnly && !ctx.disabled\n      : !!(ctx.record && ctx.collection && typeof ctx.api?.request === 'function'))\n  : false;\nlet saving = false;\n\nasync function save(newRaw) {\n  if (isFormField) {\n    // Trong form: chỉ ghi vào giá trị form — bấm Save của form mới thực sự lưu\n    ctx.setValue(newRaw);\n    return;\n  }\n  const tk = ctx.collection?.getFilterByTK?.(ctx.record);\n  if (tk === null || tk === undefined) throw new Error('Không xác định được khóa của record');\n  await ctx.api.request({\n    url: `${ctx.collection.name}:update`,\n    method: 'post',\n    params: { filterByTk: tk },\n    data: { [FIELD]: newRaw },\n  });\n  try { ctx.record[FIELD] = newRaw; } catch (_) { /* record read-only thì bỏ qua */ }\n}\n\nfunction draw(raw) {\n  lastDrawn = raw; // để listener value-change không vẽ trùng\n  if (!Number.isFinite(raw)) {\n    output('<span style=\"color:#bfbfbf\">-</span>');\n    return;\n  }\n\n  const percent = Math.max(0, Math.min(100, (raw / MAX) * 100));\n  const color = (THRESHOLDS.find((t) => percent >= t.min) || THRESHOLDS.at(-1)).color;\n\n  const widthStyle = BAR_WIDTH > 0 ? `width:${BAR_WIDTH}px` : 'flex:1;min-width:60px';\n  const cursor = canEdit ? 'cursor:pointer' : '';\n  const textHtml = SHOW_TEXT\n    ? `<span style=\"color:${color};font-weight:500;font-size:12px;min-width:${DECIMALS > 0 ? 48 : 36}px;text-align:right\">${percent.toFixed(DECIMALS)}%</span>`\n    : '';\n\n  output(`\n    <div title=\"${raw} / ${MAX}${canEdit ? ' — bấm để chỉnh' : ''}\" style=\"display:flex;align-items:center;gap:8px\">\n      <div data-bar style=\"${widthStyle};height:${BAR_HEIGHT}px;background:#f0f0f0;border-radius:${BAR_HEIGHT / 2}px;overflow:hidden;${cursor}\">\n        <div style=\"width:${percent}%;height:100%;background:${color};border-radius:${BAR_HEIGHT / 2}px;transition:width .3s ease;pointer-events:none\"></div>\n      </div>\n      ${textHtml}\n    </div>\n  `);\n\n  if (!canEdit) return;\n  const track = ctx.element?.querySelector?.('[data-bar]');\n  if (!track) return;\n  track.addEventListener('click', async (e) => {\n    e.stopPropagation();\n    if (saving) return;\n    saving = true;\n    try {\n      // % mới = vị trí bấm trên thanh, làm tròn theo STEP\n      const rect = track.getBoundingClientRect();\n      let p = ((e.clientX - rect.left) / rect.width) * 100;\n      p = Math.max(0, Math.min(100, Math.round(p / STEP) * STEP));\n      const newRaw = Number(((p / 100) * MAX).toFixed(4)); // tránh sai số 0.30000000004\n      await save(newRaw);\n      draw(newRaw);\n    } catch (err) {\n      ctx.message?.error?.(err.message || 'Cập nhật thất bại');\n    } finally {\n      saving = false;\n    }\n  });\n}\n\n// Giá trị ban đầu: form dùng ctx.getValue(), JS Column dùng ctx.record, JS Field dùng ctx.value\nlet lastDrawn;\ndraw(Number((isFormField ? ctx.getValue() : ctx.record ? ctx.record?.[FIELD] : ctx.value) ?? NaN));\n\n// Form: vẽ lại khi giá trị bị đổi từ bên ngoài (reset form, linkage, submit xong...)\nif (isFormField) {\n  ctx.element?.addEventListener?.('js-field:value-change', (ev) => {\n    const v = Number(ev?.detail ?? NaN);\n    if (v === lastDrawn || (Number.isNaN(v) && Number.isNaN(lastDrawn))) return;\n    draw(v);\n  });\n}\n"
  },
  {
    "ref": "ptdl/field/tags",
    "prefix": "tags",
    "label": "Tags / array",
    "description": "Multi-select hoặc m2m → dãy tag màu, cắt bớt \"+N\"; bỏ tag được trong form.",
    "contexts": [
      "JSEditableFieldModel",
      "FormJSFieldItemModel",
      "JSColumnModel",
      "JSFieldModel"
    ],
    "content": "/**\n * Tags / Array display — Run JS (JS Column / JS Field / JS editable field trong form)\n * Hiển thị field multi-select hoặc quan hệ m2m thành dãy tag màu, cắt bớt nếu quá dài (\"+N\").\n * EDITABLE = true: cho phép bấm \"x\" để bỏ 1 tag — CHỈ áp dụng khi giá trị là mảng chuỗi/số đơn giản\n * (multi-select enum) VÀ đang chạy trong JS editable field của form (ghi qua ctx.setValue, bấm Save mới lưu).\n * Với mảng object (quan hệ m2m) mặc định chỉ hiển thị — xóa quan hệ nên dùng picker gốc của NocoBase.\n */\n\n// ================== CẤU HÌNH ==================\nconst FIELD       = 'tags';  // tên field trên record (JS Column) — multi-select hoặc quan hệ m2m\nconst LABEL_KEY    = 'label'; // nếu phần tử là object (m2m), lấy nhãn theo key này (thử thêm 'name'/'title' nếu thiếu)\nconst EDITABLE     = true;    // true: cho bỏ tag (chỉ hiệu lực với mảng giá trị đơn giản trong form)\nconst MAX_VISIBLE  = 3;       // số tag hiện tối đa, còn lại gộp thành \"+N\"\nconst SIZE         = 'small'; // 'small' | 'default'\nconst EMPTY_TEXT   = '-';\n// Màu cố định theo nhãn (không khai báo → tự suy màu ổn định từ hash(nhãn))\nconst COLORS = {\n  // 'Urgent': '#f5222d',\n  // 'Low': '#8c8c8c',\n};\nconst PALETTE = ['#1677ff', '#52c41a', '#faad14', '#f5222d', '#722ed1', '#13c2c2', '#eb2f96', '#fa8c16'];\n\n// ==============================================\nconst output = (html) =>\n  typeof ctx.render === 'function' ? ctx.render(html) : (ctx.element.innerHTML = html);\n\nconst isFormField = typeof ctx.setValue === 'function' && typeof ctx.getValue === 'function';\nconst canEdit = EDITABLE && isFormField && !ctx.readOnly && !ctx.disabled;\n\nfunction hashColor(text) {\n  let h = 0;\n  for (let i = 0; i < text.length; i++) h = (h * 31 + text.charCodeAt(i)) >>> 0;\n  return PALETTE[h % PALETTE.length];\n}\n\nfunction toLabel(item) {\n  if (item == null) return '';\n  if (typeof item === 'object') {\n    return String(item[LABEL_KEY] ?? item.name ?? item.title ?? item.label ?? item.id ?? '').trim();\n  }\n  return String(item).trim();\n}\n\n// true nếu toàn bộ phần tử là string/number (đủ an toàn để ghi thẳng lại qua setValue khi xóa tag)\nfunction isSimpleArray(arr) {\n  return arr.every((it) => typeof it === 'string' || typeof it === 'number');\n}\n\nfunction normalize(raw) {\n  if (raw == null || raw === '') return [];\n  if (Array.isArray(raw)) return raw;\n  if (typeof raw === 'string') return raw.split(',').map((s) => s.trim()).filter(Boolean);\n  return [raw];\n}\n\nfunction draw(rawValue) {\n  const list = normalize(rawValue);\n  if (!list.length) {\n    output(`<span style=\"color:#bfbfbf\">${EMPTY_TEXT}</span>`);\n    return;\n  }\n\n  const editableHere = canEdit && isSimpleArray(list);\n  const pad = SIZE === 'small' ? '0 6px' : '2px 10px';\n  const fontSize = SIZE === 'small' ? '12px' : '13px';\n  const visible = list.slice(0, MAX_VISIBLE);\n  const restCount = list.length - visible.length;\n  const restLabels = list.slice(MAX_VISIBLE).map(toLabel).join(', ');\n\n  const tagHtml = (item, idx) => {\n    const label = toLabel(item) || '?';\n    const color = COLORS[label] || hashColor(label);\n    const closeBtn = editableHere\n      ? `<span data-remove=\"${idx}\" style=\"margin-left:4px;cursor:pointer;opacity:.7\">×</span>`\n      : '';\n    return `\n      <span style=\"display:inline-flex;align-items:center;padding:${pad};border-radius:4px;font-size:${fontSize};line-height:1.8;background:${color}1a;color:${color};border:1px solid ${color}55;white-space:nowrap\">\n        ${label}${closeBtn}\n      </span>\n    `;\n  };\n\n  const tagsHtml = visible.map(tagHtml).join('');\n  const moreHtml = restCount > 0\n    ? `<span title=\"${restLabels}\" style=\"font-size:${fontSize};color:#8c8c8c;padding:${pad}\">+${restCount}</span>`\n    : '';\n\n  output(`\n    <span data-tags style=\"display:inline-flex;flex-wrap:wrap;align-items:center;gap:4px;max-width:100%\">\n      ${tagsHtml}${moreHtml}\n    </span>\n  `);\n\n  if (!editableHere) return;\n  const wrap = ctx.element?.querySelector?.('[data-tags]');\n  if (!wrap) return;\n  wrap.addEventListener('click', (e) => {\n    const btn = e.target?.closest?.('[data-remove]');\n    if (!btn) return;\n    e.stopPropagation();\n    const idx = Number(btn.getAttribute('data-remove'));\n    const next = list.slice(0, idx).concat(list.slice(idx + 1));\n    ctx.setValue(next);\n    draw(next);\n  });\n}\n\n// Giá trị ban đầu: form dùng ctx.getValue(), JS Column dùng ctx.record, JS Field dùng ctx.value\ndraw(isFormField ? ctx.getValue() : ctx.record ? ctx.record?.[FIELD] : ctx.value);\n\n// Form: vẽ lại khi giá trị bị đổi từ bên ngoài (reset form, linkage, submit xong...)\nif (isFormField) {\n  ctx.element?.addEventListener?.('js-field:value-change', (ev) => {\n    draw(ev?.detail);\n  });\n}\n"
  },
  {
    "ref": "ptdl/field/avatar",
    "prefix": "avatar",
    "label": "Avatar + text",
    "description": "Ảnh đại diện (field ảnh hoặc quan hệ user) + tên bên cạnh, fallback initials khi thiếu ảnh.",
    "contexts": [
      "JSEditableFieldModel",
      "FormJSFieldItemModel",
      "JSColumnModel",
      "JSFieldModel"
    ],
    "content": "/**\n * Avatar + text — Run JS (JS Column / JS Field / JS editable field trong form)\n * Hiển thị ảnh đại diện (từ field ảnh hoặc field quan hệ user) + tên bên cạnh.\n * Không có ảnh → fallback initials (chữ cái đầu) trên nền màu suy từ tên (ổn định, không random).\n * Chỉ hiển thị — không chỉnh sửa (đổi người/ảnh nên dùng field picker gốc của NocoBase).\n */\n\n// ================== CẤU HÌNH ==================\n// Đường dẫn (dot path) tính TỪ record, không phải từ FIELD — để trống nếu field nằm phẳng ngay trên record.\n// Ví dụ quan hệ m2o \"createdBy\" trả về { id, nickname, avatar: { url } }:\n//   AVATAR_PATH = 'createdBy.avatar.url'\n//   NAME_PATH   = 'createdBy.nickname'\n// Ví dụ field phẳng trên record (avatarUrl, fullName):\n//   AVATAR_PATH = 'avatarUrl'\n//   NAME_PATH   = 'fullName'\nconst AVATAR_PATH = 'createdBy.avatar.url';\nconst NAME_PATH   = 'createdBy.nickname';\nconst SIZE        = 24;       // kích thước avatar (px)\nconst SHAPE       = 'circle'; // 'circle' | 'square'\nconst SHOW_NAME   = true;     // hiện tên bên cạnh avatar\nconst MAX_LEN     = 20;       // cắt bớt tên nếu quá dài (0 = không cắt)\nconst EMPTY_TEXT  = '-';      // hiển thị khi không có tên/avatar\n// Bảng màu nền cho fallback initials — chọn theo hash(tên) nên cùng 1 tên luôn ra cùng 1 màu\nconst PALETTE = ['#1677ff', '#52c41a', '#faad14', '#f5222d', '#722ed1', '#13c2c2', '#eb2f96', '#fa8c16'];\n\n// ==============================================\nfunction get(obj, path) {\n  if (!obj || !path) return undefined;\n  return path.split('.').reduce((acc, key) => (acc == null ? undefined : acc[key]), obj);\n}\n\nfunction hashColor(text) {\n  let h = 0;\n  for (let i = 0; i < text.length; i++) h = (h * 31 + text.charCodeAt(i)) >>> 0;\n  return PALETTE[h % PALETTE.length];\n}\n\nfunction initials(name) {\n  const parts = name.trim().split(/\\s+/).filter(Boolean);\n  if (!parts.length) return '?';\n  if (parts.length === 1) return parts[0].slice(0, 2).toUpperCase();\n  return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();\n}\n\nconst output = (html) =>\n  typeof ctx.render === 'function' ? ctx.render(html) : (ctx.element.innerHTML = html);\n\n// Nguồn record: JS Column dùng ctx.record; JS editable field trong form dùng ctx.getValue()/ctx.record nếu có;\n// JS Field (detail, không editable) chỉ có ctx.value + ctx.record.\nconst record = ctx.record || {};\nconst rawName = get(record, NAME_PATH);\nconst avatarUrl = get(record, AVATAR_PATH);\nconst name = rawName == null ? '' : String(rawName).trim();\n\nif (!name && !avatarUrl) {\n  output(`<span style=\"color:#bfbfbf\">${EMPTY_TEXT}</span>`);\n  return;\n}\n\nconst radius = SHAPE === 'circle' ? '50%' : '4px';\nconst displayName = MAX_LEN > 0 && name.length > MAX_LEN ? name.slice(0, MAX_LEN) + '…' : name;\n\nlet avatarHtml;\nif (avatarUrl) {\n  avatarHtml = `<img src=\"${avatarUrl}\" alt=\"${name}\" style=\"width:${SIZE}px;height:${SIZE}px;border-radius:${radius};object-fit:cover;flex:none\" />`;\n} else {\n  const bg = hashColor(name || '?');\n  avatarHtml = `\n    <span style=\"display:inline-flex;align-items:center;justify-content:center;width:${SIZE}px;height:${SIZE}px;border-radius:${radius};background:${bg};color:#fff;font-size:${Math.max(10, SIZE * 0.42)}px;font-weight:600;flex:none;line-height:1\">\n      ${initials(name || '?')}\n    </span>\n  `;\n}\n\nconst nameHtml = SHOW_NAME\n  ? `<span style=\"overflow:hidden;text-overflow:ellipsis;white-space:nowrap\">${displayName}</span>`\n  : '';\n\noutput(`\n  <span title=\"${name}\" style=\"display:inline-flex;align-items:center;gap:6px;max-width:100%\">\n    ${avatarHtml}${nameHtml}\n  </span>\n`);\n"
  },
  {
    "ref": "ptdl/field/number-format",
    "prefix": "number-format",
    "label": "Number format",
    "description": "Định dạng số: phân tách nghìn (comma/dot chuẩn VN), số thập phân, tiền tệ/hậu tố.",
    "contexts": [
      "JSColumnModel",
      "JSFieldModel"
    ],
    "content": "// =================== CẤU HÌNH (sửa tuỳ field) ===================\nconst STYLE    = 'comma'; // 'comma' => 1,234,567.89 | 'dot' => 1.234.567,89 (chuẩn VN)\nconst DECIMALS = 0;       // số chữ số thập phân (0 = số nguyên)\nconst PREFIX   = '';      // tiền tố, vd '₫ '\nconst SUFFIX   = '';      // hậu tố, vd ' đ' hoặc ' %'\n// ===============================================================\n\nfunction NumberFormatField() {\n  const React = ctx.React;\n  const { InputNumber } = ctx.antd;\n  const [value, setValue] = React.useState(ctx.getValue?.() ?? null);\n\n  // Đồng bộ khi giá trị bị đổi từ bên ngoài (reset form, nạp record...)\n  React.useEffect(() => {\n    const handler = (ev) => setValue(ev?.detail ?? null);\n    ctx.element?.addEventListener('js-field:value-change', handler);\n    return () => ctx.element?.removeEventListener('js-field:value-change', handler);\n  }, []);\n\n  const S = STYLE === 'dot' ? { t: '.', d: ',' } : { t: ',', d: '.' };\n\n  const format = (val) => {\n    if (val === undefined || val === null || val === '') return '';\n    const s = String(val);\n    const neg = s.trim().startsWith('-');\n    const p = s.replace('-', '').split('.');\n    const intPart = (p[0] || '0').replace(/\\B(?=(\\d{3})+(?!\\d))/g, S.t);\n    let out = intPart;\n    if (p[1] !== undefined && p[1] !== '') out += S.d + p[1];\n    return (neg ? '-' : '') + PREFIX + out + SUFFIX;\n  };\n\n  const parse = (val) => {\n    if (!val) return '';\n    let v = String(val);\n    if (PREFIX) v = v.split(PREFIX).join('');\n    if (SUFFIX) v = v.split(SUFFIX).join('');\n    v = v.split(S.t).join('');                   // bỏ ngăn cách nghìn\n    if (S.d !== '.') v = v.split(S.d).join('.');  // đưa dấu thập phân về '.'\n    return v.replace(/[^\\d.-]/g, '');\n  };\n\n  if (ctx.readOnly) return <span>{format(value)}</span>;\n\n  return (\n    <InputNumber\n      style={{ width: '100%' }}\n      value={value}\n      onChange={(v) => { setValue(v); ctx.setValue?.(v); }}\n      disabled={ctx.disabled}\n      controls={false}\n      precision={DECIMALS}\n      formatter={format}\n      parser={parse}\n    />\n  );\n}\n\nctx.render(<NumberFormatField />);\n"
  },
  {
    "ref": "ptdl/field/status-format",
    "prefix": "status-format",
    "label": "Status tag (map)",
    "description": "Map value → nhãn + màu tag (khai báo MAP trong code).",
    "contexts": [
      "JSColumnModel",
      "JSFieldModel"
    ],
    "content": "// ============ CẤU HÌNH — đặt RunJS này LÊN CỘT \"status\" ============\n// key viết THƯỜNG. Nếu status là field Select có value khác thì sửa key cho khớp.\nconst MAP = {\n  success: { color: '#16a34a', bg: 'rgba(22,163,74,0.12)', icon: 'check', label: 'Success' },\n  fail:    { color: '#dc2626', bg: 'rgba(220,38,38,0.12)', icon: 'x',     label: 'Fail' },\n};\n// =================================================================\n\nfunction StatusCell() {\n  const React = ctx.React;\n\n  // Lấy giá trị status: ưu tiên value của chính field; fallback đọc từ record\n  let raw = ctx.getValue?.();\n  if ((raw == null || raw === '') && ctx.record) raw = ctx.record.status;\n  // GỠ LỖI: bỏ // ở dòng dưới để xem ctx cung cấp gì (mở Console F12) nếu ô hiện \"—\"\n  // console.log('[status] value=', ctx.getValue?.(), ' record=', ctx.record, ' keys=', Object.keys(ctx));\n\n  const cfg = MAP[String(raw ?? '').trim().toLowerCase()];\n  if (!cfg) return <span style={{ color: '#999' }}>{raw == null || raw === '' ? '—' : String(raw)}</span>;\n\n  // Icon Lucide vẽ thẳng bằng SVG (không cần plugin icon)\n  const svgProps = {\n    width: '1em', height: '1em', viewBox: '0 0 24 24', fill: 'none',\n    stroke: 'currentColor', strokeWidth: 2, strokeLinecap: 'round', strokeLinejoin: 'round',\n    style: { flexShrink: 0 },\n  };\n  const icon = cfg.icon === 'check'\n    ? <svg {...svgProps}><circle cx=\"12\" cy=\"12\" r=\"10\" /><path d=\"m9 12 2 2 4-4\" /></svg>\n    : <svg {...svgProps}><circle cx=\"12\" cy=\"12\" r=\"10\" /><path d=\"m15 9-6 6\" /><path d=\"m9 9 6 6\" /></svg>;\n\n  return (\n    <span style={{\n      display: 'inline-flex', alignItems: 'center', gap: 6,\n      color: cfg.color, fontWeight: 600, background: cfg.bg,\n      borderRadius: 999, padding: '2px 10px', lineHeight: 1.7,\n    }}>\n      {icon}{cfg.label}\n    </span>\n  );\n}\n\nctx.render(<StatusCell />);\n"
  }
];
